import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { Item, Location } from '../../core/models';

/**
 * Item detail — shows an item's computed on-hand total and the per-location
 * stock breakdown. Managers get edit/delete + quick movement actions.
 */
@Component({
  selector: 'app-item-detail',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './item-detail.component.html',
  styleUrl: './item-detail.component.css',
})
export class ItemDetailComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);
  readonly itemId = signal<string>('');

  readonly locations = signal<Location[]>([
    { id: 'l1', name: 'Main Warehouse', zone: 'A' },
    { id: 'l2', name: 'Storefront', zone: 'B' },
    { id: 'l3', name: 'Overflow Depot', zone: 'C' },
  ]);

  // Mock catalog keyed by id; the API returns a single item on GET /items/:id.
  readonly items = signal<Item[]>([
    { id: 'i1', sku: 'SKU-1001', name: 'Steel Bolt M6', unit: 'pcs', reorderAt: 100, onHand: 340,
      description: 'Zinc-plated hex bolt, 6mm thread.',
      stockLevels: [
        { id: 's1', itemId: 'i1', locationId: 'l1', qty: 260 },
        { id: 's2', itemId: 'i1', locationId: 'l2', qty: 80 },
      ] },
    { id: 'i2', sku: 'SKU-1002', name: 'Copper Wire 2mm', unit: 'm', reorderAt: 200, onHand: 85,
      description: 'Bare copper wire, 2mm gauge, sold by the metre.',
      stockLevels: [{ id: 's3', itemId: 'i2', locationId: 'l1', qty: 85 }] },
    { id: 'i3', sku: 'SKU-1003', name: 'PVC Pipe 20mm', unit: 'pcs', reorderAt: 50, onHand: 12,
      description: '3m lengths of 20mm PVC pipe.',
      stockLevels: [{ id: 's4', itemId: 'i3', locationId: 'l2', qty: 12 }] },
    { id: 'i6', sku: 'SKU-1006', name: 'Rubber Gasket 50mm', unit: 'pcs', reorderAt: 80, onHand: 0,
      description: 'Nitrile rubber gasket, 50mm outer diameter.',
      stockLevels: [] },
  ]);

  readonly item = computed<Item | undefined>(() =>
    this.items().find((it) => it.id === this.itemId()),
  );

  constructor(
    public auth: AuthService,
    private route: ActivatedRoute,
  ) {}

  ngOnInit(): void {
    this.route.paramMap.subscribe((p) => this.itemId.set(p.get('id') ?? ''));
  }

  isLow(it: Item): boolean {
    return (it.onHand ?? 0) < it.reorderAt;
  }

  locationName(id: string): string {
    return this.locations().find((l) => l.id === id)?.name ?? id;
  }
}
